&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 调整形状&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;99&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;100&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# 计算最终的注意力加权&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;101&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        x &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; x &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; x_h_attn &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; x_w_attn&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;102&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;103&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# 基于自注意力的通道注意力&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;104&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# 减少计算量&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;105&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        y &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;down_func&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;x&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 下采样&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;106&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        y &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;conv_d&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 维度转换&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;107&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        _&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; _&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; h_&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; w_ &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; y&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;size&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 获取形状&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;108&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;109&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# 先归一化，然后重塑 -&gt; (B, H, W, C) -&gt; (B, C, H * W)，并生成 q, k 和 v&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;110&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        y &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;norm&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 归一化&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;111&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        q &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;q&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 计算查询&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;112&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        k &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;k&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 计算键&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;113&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        v &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;v&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;y&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 计算值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;114&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# (B, C, H, W) -&gt; (B, head_num, head_dim, N)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;115&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        q &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; rearrange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;q&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;b (head_num head_dim) h w -&gt; b head_num head_dim (h w)&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; head_num&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;head_num&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;116&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                      head_dim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;head_dim&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;117&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        k &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; rearrange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;k&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;b (head_num head_dim) h w -&gt; b head_num head_dim (h w)&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; head_num&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;head_num&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;118&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                      head_dim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;head_dim&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;119&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        v &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; rearrange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;v&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;b (head_num head_dim) h w -&gt; b head_num head_dim (h w)&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; head_num&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;head_num&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;120&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;                      head_dim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;head_dim&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;121&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;122&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# 计算注意力&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;123&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        attn &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; q @ k&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;transpose&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;scaler  &lt;span class=&#34;token comment&#34;&gt;# 点积注意力计算&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;124&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        attn &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;attn_drop&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;attn&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;softmax&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;dim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 应用注意力丢弃&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;125&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# (B, head_num, head_dim, N)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;126&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        attn &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; attn @ v  &lt;span class=&#34;token comment&#34;&gt;# 加权值&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;127&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# (B, C, H_, W_)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;128&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        attn &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; rearrange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;attn&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;b head_num head_dim (h w) -&gt; b (head_num head_dim) h w&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; h&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;h_&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; w&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token builtin&#34;&gt;int&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;w_&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;129&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token comment&#34;&gt;# (B, C, 1, 1)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;130&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        attn &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; attn&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;mean&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; keepdim&lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt;&lt;span class=&#34;token boolean&#34;&gt;True&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 求平均&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;131&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        attn &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; self&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;ca_gate&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;attn&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 应用通道注意力门控&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;132&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;        &lt;span class=&#34;token keyword&#34;&gt;return&lt;/span&gt; attn &lt;span class=&#34;token operator&#34;&gt;*&lt;/span&gt; x  &lt;span class=&#34;token comment&#34;&gt;# 返回加权后的输入&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;注释来自：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3d1bGluZzEyOS9hcnRpY2xlL2RldGFpbHMvMTQzMzY1NzUz&#34;&gt;https://blog.csdn.net/wuling129/article/details/143365753&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;ela&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#ela&#34;&gt;#&lt;/a&gt; ELA&lt;/h1&gt;
&lt;p&gt;【ELA: Efficient Local Attention for Deep Convolutional Neural Networks】：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9hcnhpdi5vcmcvYWJzLzI0MDMuMDExMjM=&#34;&gt;https://arxiv.org/abs/2403.01123&lt;/span&gt;&lt;/p&gt;
&lt;h1 id=&#34;张量操纵神器einops&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#张量操纵神器einops&#34;&gt;#&lt;/a&gt; 张量操纵神器 einops&lt;/h1&gt;
&lt;p&gt;einops 被称为 “张量操作的神器”，因为它把复杂的  &lt;code&gt;view&lt;/code&gt; 、 &lt;code&gt;reshape&lt;/code&gt; 、 &lt;code&gt;transpose&lt;/code&gt;  和  &lt;code&gt;permute&lt;/code&gt;  组合简化成了一种&lt;strong&gt;可读性极强&lt;/strong&gt;的描述性。&lt;/p&gt;
&lt;p&gt;它最常用的三个函数是：&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;strong&gt; &lt;code&gt;rearrange&lt;/code&gt; &lt;/strong&gt;: 重排、拆分、合并维度（最常用）。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt; &lt;code&gt;reduce&lt;/code&gt; &lt;/strong&gt;: 结合了池化 / 均值 / 最大值的维度缩减。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt; &lt;code&gt;repeat&lt;/code&gt; &lt;/strong&gt;: 沿着某个维度复制数据。&lt;/li&gt;
&lt;/ol&gt;
&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;input_tensor &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; torch&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;rand&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;128&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;input_tensor&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;permute&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;3&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;2&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;shape&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;rearrange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;input_tensor&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token string&#34;&gt;&#39;b c h w -&gt; b c w h&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;shape&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;figure class=&#34;highlight python&#34;&gt;&lt;figcaption data-lang=&#34;python&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;input_tensor &lt;span class=&#34;token operator&#34;&gt;=&lt;/span&gt; torch&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;rand&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;256&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;128&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;  &lt;span class=&#34;token comment&#34;&gt;# 1,32,256*128&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;2&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;input_tensor&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;view&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token number&#34;&gt;32&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt; &lt;span class=&#34;token operator&#34;&gt;-&lt;/span&gt;&lt;span class=&#34;token number&#34;&gt;1&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;shape&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;tr&gt;&lt;td data-num=&#34;3&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token keyword&#34;&gt;print&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;rearrange&lt;span class=&#34;token punctuation&#34;&gt;(&lt;/span&gt;input_tensor&lt;span class=&#34;token punctuation&#34;&gt;,&lt;/span&gt;  &lt;span class=&#34;token string&#34;&gt;&#39;b c h w -&gt; b c (w h)&#39;&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;span class=&#34;token punctuation&#34;&gt;.&lt;/span&gt;shape&lt;span class=&#34;token punctuation&#34;&gt;)&lt;/span&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;详情请参考官方仓库与文档：&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL2Fyb2dvemhuaWtvdi9laW5vcHMvdHJlZS9tYWlu&#34;&gt;https://github.com/arogozhnikov/einops/tree/main&lt;/span&gt;&lt;/p&gt;

 &lt;h1 id=&#34;movima-hybrid-cnn-vision-mamba-network-for-lightweight-semantic-segmentation-of-multimodal-remote-sensing-images&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#movima-hybrid-cnn-vision-mamba-network-for-lightweight-semantic-segmentation-of-multimodal-remote-sensing-images&#34;&gt;#&lt;/a&gt; MoViM：A Hybrid CNN Vision Mamba Network  for Lightweight Semantic Segmentation of  Multimodal Remote Sensing Images&lt;/h1&gt;
&lt;blockquote&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9pZWVleHBsb3JlLmllZWUub3JnL2RvY3VtZW50LzExMjA4NjIx&#34;&gt;【Original Link】 MoViM: A Hybrid CNN Vision Mamba Network for Lightweight Semantic Segmentation of Multimodal Remote Sensing Images&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;Published in: IEEE Geoscience and Remote Sensing Letters ( Volume: 22)&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly93d3cuc2NpZW5jZWRpcmVjdC5jb20vam91cm5hbC9pc3Bycy1qb3VybmFsLW9mLXBob3RvZ3JhbW1ldHJ5LWFuZC1yZW1vdGUtc2Vuc2luZy92b2wvMjExL3N1cHBsL0M=&#34;&gt;Volume 211&lt;/span&gt;, May 2024, Pages 1-34&lt;/li&gt;
&lt;li&gt;Authors
&lt;ul&gt;
&lt;li&gt;Wen-Liang Du&lt;/li&gt;
&lt;li&gt;Shuo Tang&lt;/li&gt;
&lt;li&gt;Rui Yao&lt;/li&gt;
&lt;li&gt;Zeyu An&lt;/li&gt;
&lt;li&gt;Yong Zhou&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;abstract&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#abstract&#34;&gt;#&lt;/a&gt; Abstract&lt;/h2&gt;
&lt;p&gt;The “Others” category in multimodal remote sensing images is characterized by high intra-class variability. Therefore, existing lightweight semantic segmentation models struggle with this category due to limitations in capturing both local details and global dependencies efficiently. We propose MoViM, a lightweight model that integrates a hybrid Vision Mamba (ViM) and CNN backbone to capture global contextual information and local details effectively. In addition, the MoViM also features an Inverted Stem for efficient multimodal fusion, a Global Semantics Extraction (GSE) module for enhanced global feature representation, and a Global-Local Feature Fusion (GLF) module for context-aware feature integration. Extensive experiments on WHU-OPT-SAR and Potsdam datasets demonstrate that MoViM achieves state-of-the-art performance, particularly in the “Others” category, while maintaining low computational complexity. Our codes are available at &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL1dlbmxpYW5nRHUvTW9WaU0=&#34;&gt;https://github.com/WenliangDu/MoViM&lt;/span&gt;.&lt;/p&gt;
&lt;p&gt;多模态遥感图像中的 “其他” 类别具有高度的类别内变异性。因此，现有的轻量级语义分割模型在处理该类别时存在困难，因为在高效捕捉局部细节和全局依赖方面存在局限。我们提出了 MoViM，一种轻量级模型，集成了混合的 Vision Mamba（&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saWJyYXJ5LnNjaG9sYXJjeS5jb20vdHJ5Iw==&#34;&gt;ViM&lt;/span&gt;）和 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saWJyYXJ5LnNjaG9sYXJjeS5jb20vdHJ5Iw==&#34;&gt;CNN&lt;/span&gt; 骨干网，以有效捕捉全球情境信息和本地细节。此外，MoViM 还配备了&lt;strong&gt;倒置茎&lt;/strong&gt;以实现高效的多模态融合 ，一个&lt;strong&gt;全局语义提取（&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saWJyYXJ5LnNjaG9sYXJjeS5jb20vdHJ5Iw==&#34;&gt;GSE&lt;/span&gt;）模块&lt;/strong&gt;以增强全局特征表示，以及一个&lt;strong&gt;全局 - 局部特征融合（&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saWJyYXJ5LnNjaG9sYXJjeS5jb20vdHJ5Iw==&#34;&gt;GLF&lt;/span&gt;）模块&lt;/strong&gt;，用于上下文感知特征集成。在 WHU-OPT-SAR 和 Potsdam 数据集上的大量实验表明，MoViM 在 “其他” 类别中实现了最先进的性能，同时保持了低计算复杂度。我们的代码可在 &lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9naXRodWIuY29tL1dlbmxpYW5nRHUvTW9WaU0=&#34;&gt;https://github.com/WenliangDu/MoViM&lt;/span&gt; 获取。&lt;/p&gt;
&lt;p&gt;Index Terms—Hybrid convolutional neural network (CNN) vision mamba (ViM), lightweight semantic segmentation, multimodal remote sensing.&lt;/p&gt;
&lt;p&gt;指标术语 —— 混合卷积神经网络（CNN）、视觉曼巴（ViM）、轻量级语义分割、多模态遥感。&lt;/p&gt;
&lt;h2 id=&#34;introduction&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#introduction&#34;&gt;#&lt;/a&gt; INTRODUCTION&lt;/h2&gt;
&lt;p&gt;The semantic segmentation of satellite-based multisource remote sensing images achieves significant improvements in the accuracy of surface information extraction by integrating data from heterogeneous sensors, such as optical, synthetic aperture radar (SAR), and infrared radiation. Developing lightweight models is crucial for enabling real-time remote sensing image interpretation on satellites.&lt;/p&gt;
&lt;p&gt;基于卫星的多源遥感图像的语义分割通过整合光学、合成孔径雷达（SAR）和红外辐射等异构传感器的数据，显著提升了表面信息提取的准确性。开发轻量化模型对于实现卫星实时遥感图像解读至关重要。&lt;/p&gt;
&lt;p&gt;Existing lightweight semantic segmentation models can mainly be categorized into two types: based on convolutional neural networks (CNNs) and based on hybrid architectures combining CNN and attention.&lt;/p&gt;
&lt;p&gt;现有的轻量级语义分割模型主要可分为两类：基于卷积神经网络（CNN）和基于结合 CNN 与注意力的混合架构。&lt;/p&gt;
&lt;p&gt;CNN-based architectures (e.g., LSKNet) excel at capturing local details but inherently struggle to model long-range dependencies, leading to an incomplete global feature representation. Hybrid models, such as TopFormer, SegMan , and MobileMamba , attempt to represent local and global feature encoding using dynamic token aggregation or state-space modeling. Nevertheless, lightweight models commonly face a significant challenge: they struggle to effectively represent the “others” category, which typically encompasses highly diverse and nonfixed targets. Fig. 1 illustrates the examples of the “others” category in WHU-OPT-SAR dataset, along with the class distribution within the dataset. The proportion of the “others” category is nearly double that of the “road” category, underscoring the importance of evaluating lightweight methods for “others” segmentation. In addition, effectively segmenting the “others” class helps reduce the likelihood of methods misclassifying unseen content into known categories, thereby lowering the risk of overfitting [&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saWJyYXJ5LnNjaG9sYXJjeS5jb20vdHJ5I3I1&#34;&gt;5&lt;/span&gt;]. However, the high intraclass variability and visual similarity of “others” to adjacent classes (e.g., buildings, roads) significantly increase segmentation difficulties, resulting in poorer performance of lightweight methods in the “others” segmentation. Consequently, excluding “others” from the evaluation of lightweight methods has become a common but unreasonable practice.&lt;/p&gt;
&lt;p&gt;基于 CNN 的架构（例如 LSKNet）擅长捕捉局部细节，但本质上难以建模长距离依赖关系，导致全局特征表示不完整。混合模型，如 TopFormer 、SegMan 和 MobileMamba，尝试通过动态令牌聚合或状态空间建模来表示局部和全局特征编码。然而，轻量级模型通常面临重大挑战：它们难以有效代表 “其他” 类别，而该类别通常涵盖高度多样化且非固定的目标。图 1 展示了 WHU-OPT-SAR 数据集中 “其他” 类别的示例，以及该数据集内的类别分布。“其他” 类别的比例几乎是 “道路” 类别的两倍，凸显了评估轻量级方法对 “其他人” 细分的重要性。此外，有效分割 “其他 ” 类有助于减少方法将看不见内容误归为已知类别的可能性，从而降低过拟合的风险 [&lt;span class=&#34;exturl&#34; data-url=&#34;aHR0cHM6Ly9saWJyYXJ5LnNjaG9sYXJjeS5jb20vdHJ5I3I1&#34;&gt;5&lt;/span&gt;]。然而，“他者” 在类别内的高度变异性和与相邻类别（如建筑物、道路）的视觉相似性显著增加了分段难度，导致轻量级方法在 “他者” 分段中表现较差。因此，将 “他者” 排除在轻量级方法评估之外已成为一种常见但不合理的做法。&lt;/p&gt;
&lt;img data-src=&#34;../../images/paper/MoViM/1.png&#34; alt=&#34;1&#34; style=&#34;zoom:75%;&#34; /&gt;
&lt;p&gt;To tackle this challenge, we propose the MoViM method, which focuses on comprehensive global and local feature extraction and representation, aiming to improve the segmentation performance for the “others” category. Specifically, MoViM’s lightweight backbone network is inspired by the powerful local feature representation capabilities of MobileNet’s lightweight depthwise convolution and by vision mamba’s (ViM) excellent global feature modeling ability under linear attention. Consequently, we constructed a hybrid ViM-CNN backbone, designed to efficiently capture the global contextual information and local detail features of heterogeneous targets like “others.” Considering the characteristics of multisource remote sensing data, we propose an inverted stem (IS) at the start of the hybrid ViM-CNN backbone to achieve lightweight and efficient multisource feature fusion. Additionally, we design a global semantics extraction (GSEs) module to further enhance the capability to capture the global features of targets and introduce a global–local feature (GLF) fusion module to promote effective integration of the global and local features. lightweight models in semantic segmentation performance, with particularly significant improvements in the “others” category.&lt;/p&gt;
&lt;p&gt;为应对这一挑战，我们提出了 MoViM 方法，该方法侧重于全面的全局和局部特征提取与表示，旨在提升 “其他” 类别的细分性能。具体来说，MoViM 的轻量骨干网络受到了 MobileNet 轻量级深度卷积的强大局部特征表示能力以及 vision mamba（ViM）在线性关注下卓越的全局特征建模能力的启发。因此，我们构建了一个混合的 ViM-CNN 骨干网，旨在高效捕捉异构目标如 “其他” 的全球上下文信息和局部细节特征。考虑到多源遥感数据的特性，我们提出在混合 ViM-CNN 骨干的起始处采用&lt;strong&gt;倒置 stem（IS&lt;/strong&gt;），&lt;strong&gt;以实现轻量化且高效的多源特征融合&lt;/strong&gt;。此外，我们设计了一个&lt;strong&gt;全局语义提取（GSEs）模块&lt;/strong&gt;，&lt;strong&gt;进一步提升捕获目标全局特征的能力&lt;/strong&gt;，并引入&lt;strong&gt;全局 - 局部特征（GLF）融合模块&lt;/strong&gt;，促进全局与局部特征的有效整合。轻量级模型在语义分割性能上表现突出，尤其在 “其他” 类别中有显著改进。&lt;/p&gt;
&lt;p&gt;Our main contributions are summarized as follows.&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;We reveal that the main reason for the poor performance of the existing lightweight models in semantic segmentation of multisource remote sensing images is the difficulty in effectively representing the “others” category, which consists of highly diverse target collections.&lt;/li&gt;
&lt;li&gt;We design the MoViM lightweight model. By constructing the ViM-CNN hybrid backbone, integrating IS, GSE, and GLF modules, the model achieves efficient extraction and thorough fusion of both global and local features of targets, significantly enhancing the segmentation effect for the “others” category in multimodal remote sensing images&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;我们的主要贡献总结如下。&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;我们揭示，现有轻量级模型在多源遥感图像语义分割中表现不佳的主要原因，是难以有效表示 “其他” 类别，该类别包含高度多样化的目标集合。&lt;/li&gt;
&lt;li&gt;我们设计了 MoViM 轻量化模型。通过构建 ViM-CNN 混合骨干，集成 IS、GSE 和 GLF 模块，模型实现了目标的全局和局部特征的高效提取和彻底融合，显著增强了多模态遥感图像中 “其他” 类别的分割效果&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;method&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#method&#34;&gt;#&lt;/a&gt; METHOD&lt;/h2&gt;
&lt;p&gt;The architecture of the proposed MoViM is shown in Fig. 2. It includes a hybrid backbone, a GSE module, a GLF fusion module, and a lightweight decoding head adopted from [6], which performs bilinear upsampling and additive fusion of multiscale features, followed by a 1 × 1 projection.&lt;/p&gt;
&lt;p&gt;拟议的 MoViM 架构如图 2 所示。它包括一个混合主干、一个 GSE 模块、一个 GLF 融合模块，以及一个采用自 [6] 的轻量级译码头，该头执行双线性上采样和多尺度特征的加法融合，随后进行 1×1 投影。&lt;/p&gt;
&lt;img data-src=&#34;../../images/paper/MoViM/2.png&#34; alt=&#34;1&#34; style=&#34;zoom:75%;&#34; /&gt;
&lt;h3 id=&#34;a-hybrid-vim-cnn-backbone&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#a-hybrid-vim-cnn-backbone&#34;&gt;#&lt;/a&gt; A. Hybrid ViM-CNN Backbone&lt;/h3&gt;
&lt;p&gt;As shown in Fig. 2, the input multimodal images are combined along the channel dimension using simple concatenation operation to form a multimodal tensor X with size H × W ×C, where H and W represent the height and width of both the input images and X, respectively, and C is the total number of channels, equal to the sum of the channels of all input images. Then, X is fed into the IS module, which fuses multimodal features while performing downsampling.&lt;/p&gt;
&lt;p&gt;如图 2 所示，输入多模图像沿通道维度通过简单连接组合，运算形成一个多模张量 X，其大小为 W×W×C，其中 H 和 W 分别代表输入图像和 X 的高度和宽度，C 是通道总数 ，等于所有输入图像通道的总和。然后，X 被输入 IS 模块 ，后者在执行下采样时融合多模特征。&lt;/p&gt;
&lt;p&gt;The IS module utilizes the inverted residual (IR) block, composed of multiple depthwise separable convolutional units, to achieve efficient downsampling [see Fig. 3(a)]. Initially, the spatial resolution of the feature map is reduced to (H/4) × (W/4) through a 3 × 3 convolution followed by three IR blocks. This resulting feature map is sent into two pathways. The first pathway applies average pooling before the GSE module (xout (0) ), while the second pathway passes through two IR blocks and is further downsampled to (H/8) × (W/8), serving as an input to the hybrid backbone [xin(1)].&lt;/p&gt;
&lt;p&gt;IS 模块利用倒残差（IR） 块，由多个深度可分卷积单元组成，以实现高效的下采样 [见图 3（a）]。最初，特征图的空间分辨率通过 3×3 卷积和三个 IR 区块，将特征映射的空间分辨率简化为（H/4）×（W/4）。由此产生的特征图被分为两条路径。第一条路径在 GSE 模块前应用平均池化（xout （0））， 而第二条路径通过两个红外块 ，并进一步下采样至（H/8）×（W/8），作为混合骨干 [xin（1）] 的输入。&lt;/p&gt;
&lt;img data-src=&#34;../../images/paper/MoViM/3.png&#34; alt=&#34;1&#34; style=&#34;zoom:75%;&#34; /&gt;
&lt;p&gt;The remainder of the hybrid ViM-CNN backbone consists of three stages, each with two ViM-CNN blocks. In the last two stages, features are downsampled before entering two ViM-CNN blocks. The output feature of the ith stage [xout (i) ] is routed to the GSE module before undergoing average pooling, and it is also sent to the GLF module as the local feature.&lt;/p&gt;
&lt;p&gt;混合 ViM-CNN 骨干的其余部分由三个阶段组成，每个阶段包含两个 ViM-CNN 模块。 在最后两个阶段，特征在进入两个 ViM-CNN 块前先进行下采样。第 i 阶段的输出特征 [xout （i）] 在进行平均池化前会被路由到 GSE 模块，同时作为本地特征也发送到 GLF 模块。&lt;/p&gt;
&lt;p&gt;Each ViM-CNN block encompasses depthwise convolution, channelwise feature splitting, dual-branch processing, and gated fusion [see Fig. 3(b)]. The input first undergoes depthwise convolution and then splits into a global branch and DU et al.: MoVIM: A HYBRID CNN ViM NETWORK FOR LIGHTWEIGHT SEMANTIC SEGMENTATION it particularly well-suited for dense prediction tasks in multimodal remote sensing imagery. The output features from the GSE module provide global semantic guidance for the subsequent GLF module.&lt;/p&gt;
&lt;p&gt;每个 ViM-CNN 块包含深度卷积、通道特征拆分、双分支处理和门控融合 [见图 3（b）]。 输入先经历深度卷积，然后分解为全局分支，DU 等人：MoVIM：A HYBRID CNNViM 网络用于轻量级语义分割，特别适合多模态遥感图像中的密集预测任务。GSE 模块的输出特征为后续 GLF 模块提供了全局语义指导 。&lt;/p&gt;
&lt;p&gt;a local branch. The global branch employs LayerNorm and the hidden state mixer-based state space duality (HSM-SSD) module , which decreases computational cost by moving channel-mixing operations from the image-feature space to the hidden-state space. The local branch applies an IR module to preserve fine-grained spatial details. The two branches both operate on learnable residual gates&lt;/p&gt;
&lt;p&gt;&lt;span class=&#34;katex-display&#34;&gt;&lt;span class=&#34;katex&#34;&gt;&lt;span class=&#34;katex-mathml&#34;&gt;&lt;math xmlns=&#34;http://www.w3.org/1998/Math/MathML&#34; display=&#34;block&#34;&gt;&lt;semantics&gt;&lt;mtable width=&#34;100%&#34;&gt;&lt;mtr&gt;&lt;mtd width=&#34;50%&#34;&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mrow&gt;&lt;msub&gt;&lt;mover accent=&#34;true&#34;&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mo&gt;~&lt;/mo&gt;&lt;/mover&gt;&lt;mi&gt;g&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;=&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mn&gt;1&lt;/mn&gt;&lt;mo&gt;−&lt;/mo&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;g&lt;/mi&gt;&lt;/msub&gt;&lt;mo&gt;+&lt;/mo&gt;&lt;mi&gt;σ&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;mi&gt;β&lt;/mi&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo&gt;⋅&lt;/mo&gt;&lt;mtext&gt;HSM-SSD&lt;/mtext&gt;&lt;mrow&gt;&lt;mo fence=&#34;true&#34;&gt;(&lt;/mo&gt;&lt;mtext&gt;LN&lt;/mtext&gt;&lt;mo stretchy=&#34;false&#34;&gt;(&lt;/mo&gt;&lt;msub&gt;&lt;mi&gt;x&lt;/mi&gt;&lt;mi&gt;g&lt;/mi&gt;&lt;/msub&gt;&lt;mo stretchy=&#34;false&#34;&gt;)&lt;/mo&gt;&lt;mo fence=&#34;true&#34;&gt;)&lt;/mo&gt;&lt;/mrow&gt;&lt;/mrow&gt;&lt;/mtd&gt;&lt;mtd width=&#34;50%&#34;&gt;&lt;/mtd&gt;&lt;mtd&gt;&lt;mtext&gt;(1)&lt;/mtext&gt;&lt;/mtd&gt;&lt;/mtr&gt;&lt;/mtable&gt;&lt;annotation encoding=&#34;application/x-tex&#34;&gt;\tilde{x}_g = (1 - \sigma(\beta)) \cdot x_g + \sigma(\beta) \cdot \text{HSM-SSD} \left( \text{LN}(x_g) \right) \tag{1}

&lt;/annotation&gt;&lt;/semantics&gt;&lt;/math&gt;&lt;/span&gt;&lt;span class=&#34;katex-html&#34; aria-hidden=&#34;true&#34;&gt;&lt;span class=&#34;base&#34;&gt;&lt;span class=&#34;strut&#34; style=&#34;height:0.9539679999999999em;vertical-align:-0.286108em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord accent&#34;&gt;&lt;span class=&#34;vlist-t&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.6678599999999999em;&#34;&gt;&lt;span style=&#34;top:-3em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mord&#34;&gt;&lt;span class=&#34;mord mathnormal&#34;&gt;x&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span style=&#34;top:-3.35em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:3em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;accent-body&#34; style=&#34;left:-0.22222em;&#34;&gt;&lt;span class=&#34;mord&#34;&gt;~&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;msupsub&#34;&gt;&lt;span class=&#34;vlist-t vlist-t2&#34;&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.15139200000000003em;&#34;&gt;&lt;span style=&#34;top:-2.5500000000000003em;margin-right:0.05em;&#34;&gt;&lt;span class=&#34;pstrut&#34; style=&#34;height:2.7em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;sizing reset-size6 size3 mtight&#34;&gt;&lt;span class=&#34;mord mathnormal mtight&#34; style=&#34;margin-right:0.03588em;&#34;&gt;g&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-s&#34;&gt;​&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;vlist-r&#34;&gt;&lt;span class=&#34;vlist&#34; style=&#34;height:0.286108em;&#34;&gt;&lt;span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;span class=&#34;mspace&#34; style=&#34;margin-right:0.2777777777777778em;&#34;&gt;&lt;/span&gt;&lt;span class=&#34;mrel&#34;&gt;=&lt;